const areas = [
  'Bishan','Bukit Merah','Bukit Timah','Downtown Core','Geylang','Kallang',
  'Marina East','Marina South','Marine Parade','Museum','Newton','Novena',
  'Orchard','Outram','Queenstown','River Valley','Rochor','Singapore River',
  'Southern Islands','Straits View','Tanglin','Toa Payoh','Bedok','Changi',
  'Changi Bay','Pasir Ris','Paya Lebar','Tampines','Central Water Catchment',
  'Lim Chu Kang','Mandai','Sembawang','Simpang','Sungei Kadut','Woodlands',
  'Yishun','Ang Mo Kio','Hougang','North-Eastern Islands','Punggol','Seletar',
  'Sengkang','Serangoon','Boon Lay','Bukit Batok','Bukit Panjang',
  'Choa Chu Kang','Clementi','Jurong East','Jurong West','Pioneer','Tengah',
  'Tuas','Western Islands','Western Water Catchment'
];

const categories = [
  {q: 'GP clinic', batch: 'Batch 1 - Sep 2027'},
  {q: 'acute hospital', batch: 'Batch 1 - Sep 2027'},
  {q: 'clinical laboratory', batch: 'Batch 1 - Sep 2027'},
  {q: 'radiology centre', batch: 'Batch 1 - Sep 2027'},
  {q: 'nursing home', batch: 'Batch 1 - Sep 2027'},
  {q: 'community hospital', batch: 'Batch 1 - Sep 2027'},
  {q: 'specialist outpatient clinic', batch: 'Batch 2 - Sep 2028'},
  {q: 'ambulatory surgical centre', batch: 'Batch 2 - Sep 2028'},
  {q: 'dialysis centre', batch: 'Batch 2 - Sep 2028'},
  {q: 'dental clinic', batch: 'Batch 3 - Mar 2030'},
  {q: 'retail pharmacy', batch: 'Batch 3 - Mar 2030'},
  {q: 'assisted reproduction centre', batch: 'Batch 3 - Mar 2030'}
];

const combos = [];
for (const cat of categories) {
  for (const area of areas) {
    combos.push({
      search_query: cat.q + ' ' + area + ' Singapore',
      category: cat.q,
      hia_batch: cat.batch,
      area: area
    });
  }
}

combos.push({
  search_query: 'healthcare IT Singapore',
  category: 'healthcare IT Singapore',
  hia_batch: 'Vendor to HIA clients',
  area: 'Singapore'
});
combos.push({
  search_query: 'medical software Singapore',
  category: 'medical software Singapore',
  hia_batch: 'Vendor to HIA clients',
  area: 'Singapore'
});

return combos.slice(0, 5).map(c => ({json: c}));

// Get ALL Serper responses and ALL original combos
const serperItems = $input.all();
const combos = $('Generate Search Combos').all();
const now = new Date().toISOString();

const results = [];

for (let i = 0; i < serperItems.length; i++) {
  const serper = serperItems[i].json;
  const places = serper.places || [];
  const combo = (i < combos.length) ? combos[i].json : {};

  for (const p of places) {
    const name = (p.title || '').trim();
    if (!name) continue;

    let website = (p.website || p.link || '').trim();
    if (website && !website.startsWith('http')) website = 'https://' + website;
    website = website.replace(/\/+$/, '');

    results.push({
      json: {
        company_name: name,
        website_url: website,
        category: combo.category || '',
        hia_batch: combo.hia_batch || '',
        area: combo.area || '',
        discovered_at: now
      }
    });
  }
}

return results.length ? results : [{json: {company_name: '_NO_RESULTS_', _skip: true}}];

const source = $('Parse Places').item.json || {};
const fetchResponse = $json || {};
const payload = fetchResponse.body && typeof fetchResponse.body === 'object' ? fetchResponse.body : fetchResponse;
const rawContent = typeof payload === 'string' ? payload : (payload.result || payload.text || payload.data || payload.markdown || '');
const websiteContent = String(rawContent || '').substring(0, 12000);
const statusCode = Number(fetchResponse.statusCode || 0);
const finalUrl = String(source.website_url || '').trim();
const companyName = String(source.company_name || '').trim();

const body = {
  model: 'minimax/minimax-m2.7',
  temperature: 0,
  messages: [{
    role: 'user',
    content: `You are determining whether a discovered Singapore healthcare entity belongs to a different parent company or group.

Discovered company: ${companyName}
Discovered website: ${finalUrl}
Fetch status: ${statusCode}
Website content:
${websiteContent}

Return STRICT JSON only in this exact shape:
{"parent_company":"","parent_website":"","parent_domain":"","is_same_entity":true}

Rules:
- If the discovered company itself is the top-level company or brand, set is_same_entity to true and leave parent_* blank.
- Only return a parent when the content clearly shows a distinct parent company, holding company, or medical group.
- parent_website must be the official parent website when identifiable.
- parent_domain must be a bare domain like sgpaincare.com with no protocol or path.
- Do not invent a parent from weak hints.
- If the fetch status is non-2xx or the content is too thin to support a parent conclusion, return is_same_entity true and leave parent_* blank.
- Prefer the Singapore parent/group shown on the official site.
- Examples:
  - DR+ Medical & Paincare Bishan on drplus.com.sg with clear group branding for Singapore Paincare Holdings Limited -> is_same_entity false, parent_company Singapore Paincare Holdings Limited, parent_website https://sgpaincare.com/, parent_domain sgpaincare.com
  - Raffles Medical Clinic on rafflesmedicalgroup.com -> is_same_entity true
`
  }]
};

return { json: { requestBody: body, source } };

function normalizeUrl(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  return raw.startsWith('http') ? raw.replace(/\/+$/, '') : `https://${raw}`.replace(/\/+$/, '');
}

function extractDomain(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  try {
    const url = raw.startsWith('http') ? new URL(raw) : new URL(`https://${raw}`);
    return url.hostname.replace(/^www\./i, '').toLowerCase();
  } catch {
    return raw.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split('/')[0].toLowerCase();
  }
}

const responses = $input.all();
const output = [];

for (const item of responses) {
  const source = { ...(item.json?.source || {}) };
  if (!source.company_name) continue;

  const response = String(item.json?.choices?.[0]?.message?.content || '').trim();
  let parsed = {};
  try {
    parsed = JSON.parse(response);
  } catch {
    const match = response.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        parsed = JSON.parse(match[0]);
      } catch {}
    }
  }

  const operatingUrl = normalizeUrl(source.website_url);
  const operatingDomain = extractDomain(operatingUrl);
  const parentDomain = extractDomain(parsed.parent_domain || parsed.parent_website || '');
  const parentWebsite = normalizeUrl(parsed.parent_website || (parentDomain ? `https://${parentDomain}` : ''));
  const parentCompany = String(parsed.parent_company || '').trim();
  const isSameEntity = parsed.is_same_entity !== false || !parentCompany || !parentDomain || parentDomain === operatingDomain;
  const groupKey = parentDomain || operatingDomain || '';

  output.push({
    json: {
      company_name: source.company_name || '',
      website_url: operatingUrl,
      category: source.category || '',
      hia_batch: source.hia_batch || '',
      area: source.area || '',
      discovered_at: source.discovered_at || new Date().toISOString(),
      entity_type: 'operating',
      parent_company: isSameEntity ? '' : parentCompany,
      parent_domain: isSameEntity ? '' : parentDomain,
      parent_website: isSameEntity ? '' : parentWebsite,
      group_key: groupKey
    }
  });

  if (!isSameEntity) {
    output.push({
      json: {
        company_name: parentCompany,
        website_url: parentWebsite,
        category: source.category || '',
        hia_batch: source.hia_batch || '',
        area: source.area || '',
        discovered_at: source.discovered_at || new Date().toISOString(),
        entity_type: 'parent',
        parent_company: '',
        parent_domain: '',
        parent_website: '',
        group_key: groupKey
      }
    });
  }
}

return output.length ? output : [{ json: { _skip: true } }];

function normalizeUrl(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  return raw.startsWith('http') ? raw : `https://${raw}`;
}

function extractDomain(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  try {
    const url = raw.startsWith('http') ? new URL(raw) : new URL(`https://${raw}`);
    return url.hostname.replace(/^www\./i, '').toLowerCase();
  } catch {
    return raw.replace(/^https?:\/\//i, '').replace(/^www\./i, '').split('/')[0].toLowerCase();
  }
}

function keyFor(row) {
  const entityType = String(row.entity_type || 'operating').toLowerCase();
  const domain = extractDomain(row.website_url || row.parent_domain || '');
  const name = String(row.company_name || '').toLowerCase().trim();
  return [entityType, domain, name].join('|');
}

const candidates = $('Build Discovery Entities').all().filter(i => !i.json._skip);
const existing = ($input.first().json.list || []);
const existingKeys = new Set(existing.map(r => keyFor(r)).filter(Boolean));

const batchKeys = new Set();
const newItems = [];

for (const item of candidates) {
  const key = keyFor(item.json);
  if (!key || existingKeys.has(key) || batchKeys.has(key)) continue;
  batchKeys.add(key);
  newItems.push(item);
}

if (!newItems.length) return [{ json: { _skip: true } }];
return newItems;

const allItems = $input.all().filter(i => !i.json._skip);
if (!allItems.length) return [{ json: { rows: [] } }];
const all = allItems.map(i => i.json);
const chunks = [];
for (let i = 0; i < all.length; i += 100) {
  chunks.push({json: {rows: all.slice(i, i + 100)}});
}
return chunks;

const newDiscoveries = $('Dedup vs Discovery').all().filter(i => !i.json._skip);
const existingLeads = ($input.first().json.list || []);
const existingNames = new Set(existingLeads.map(r => (r.company_name || '').toLowerCase().trim()).filter(Boolean));

const batchNames = new Set();
const newLeads = [];

for (const item of newDiscoveries) {
  const name = (item.json.company_name || '').toLowerCase().trim();
  if (!name || existingNames.has(name) || batchNames.has(name)) continue;
  batchNames.add(name);
  newLeads.push({ json: { company_name: item.json.company_name, status: 'pending' } });
}

if (!newLeads.length) return [{ json: { _skip: true } }];
return newLeads;

const allItems = $input.all();
const all = allItems.map(i => i.json);
const chunks = [];
for (let i = 0; i < all.length; i += 100) {
  chunks.push({json: {rows: all.slice(i, i + 100)}});
}
return chunks.length ? chunks : [{json: {rows: []}}];
